  batch_size: PositiveIntegerSchema.default(50),

  // Retention settings
  trace_retention_days: PositiveIntegerSchema.default(90),
  archive_old_traces: z.boolean().default(true),
  compression_after_days: PositiveIntegerSchema.default(30),
});

// Performance and parallelism settings
const PerformanceTuningSchema = z.object({
  // Global parallel processing
  parallel_processing_enabled: z.boolean().default(true),
  max_parallel_emails: PositiveIntegerSchema.default(10),
  email_batch_size: PositiveIntegerSchema.default(50),

  // Stage-specific parallelism
  parallel_stages: z.array(z.enum([
    'attribute_detection',
    'rule_evaluation',
    'influence_calculation',
    'ai_routing',
    'audit_trail_generation',
  ])).default(['attribute_detection', 'rule_evaluation']),

  // Memory management
  memory_limit_mb: PositiveIntegerSchema.default(512),
  gc_threshold_mb: PositiveIntegerSchema.default(256),
  cache_size_limits: z.object({
    rule_cache_mb: PositiveIntegerSchema.default(64),
    attribute_cache_mb: PositiveIntegerSchema.default(32),
    config_cache_mb: PositiveIntegerSchema.default(16),
  }),

  // Timeout settings
  total_processing_timeout_ms: PositiveIntegerSchema.default(60000),
  stage_timeout_ms: PositiveIntegerSchema.default(10000),
  database_timeout_ms: PositiveIntegerSchema.default(5000),

  // Optimization flags
  enable_caching: z.boolean().default(true),
  enable_memoization: z.boolean().default(true),
  enable_lazy_loading: z.boolean().default(true),
  precompile_rules: z.boolean().default(true),
});

// Main processing configuration schema with all tuning parameters
export const ProcessingConfigTuningSchema = z.object({
  // Global settings
  version: PositiveIntegerSchema,
  schema_version: z.string().default('1.0.0'),
  taxonomy_notes: z.string(),

  // Stage-specific tuning parameters
  hard_assertion_tuning: HardAssertionTuningSchema.default({}),
  strong_indicator_tuning: StrongIndicatorTuningSchema.default({}),
  rule_scoring_tuning: RuleScoringTuningSchema.default({}),
  attribute_detection_tuning: AttributeDetectionTuningSchema.default({}),
  attribute_influence_tuning: AttributeInfluenceTuningSchema.default({}),
  disambiguation_tuning: DisambiguationTuningSchema.default({}),
  multi_label_tuning: MultiLabelTuningSchema.default({}),
  ai_routing_tuning: AIRoutingTuningSchema.default({}),
  audit_trail_tuning: AuditTrailTuningSchema.default({}),

  // Performance and system tuning
  performance_tuning: PerformanceTuningSchema.default({}),

  // Validation settings
  strict_validation: z.boolean().default(true),
  allow_experimental_features: z.boolean().default(false),
  compatibility_mode: z.enum(['strict', 'permissive', 'legacy']).default('strict'),

  // Monitoring and debugging
  monitoring: z.object({
    enable_metrics_collection: z.boolean().default(true),
    detailed_timing: z.boolean().default(false),
    memory_tracking: z.boolean().default(false),
    error_tracking: z.boolean().default(true),
    performance_alerts: z.object({
      slow_processing_threshold_ms: PositiveIntegerSchema.default(30000),
      high_memory_threshold_mb: PositiveIntegerSchema.default(256),
      error_rate_threshold: ProbabilitySchema.default(0.05),
    }).default({}),
  }).default({}),
});

// Simplified schema for basic processing config (backward compatibility)
export const BasicProcessingConfigSchema = z.object({
  version: PositiveIntegerSchema,
  taxonomy_notes: z.string(),

  // Essential settings only
  settings: z.object({
    initialization: z.object({
      apply_hard_assertions: z.boolean().default(true),
      seed_category_scores: z.boolean().default(true),
    }),
    rule_scoring: z.object({
      use_lexical_patterns: z.boolean().default(true),
      apply_subtype_rules: z.boolean().default(true),
      bounded_aggregation: z.boolean().default(true),
    }),
    attribute_processing: z.object({
      detect_self_sent: z.boolean().default(true),
      resolve_domains: z.boolean().default(true),
      derive_context_flags: z.boolean().default(true),
    }),
    disambiguation: z.object({
      pairwise_adjustments: z.boolean().default(true),
      confidence_gap_threshold: ProbabilitySchema.default(0.1),
    }),
    multi_label_selection: z.object({
      max_labels: PositiveIntegerSchema.default(3),
      min_secondary_confidence: ProbabilitySchema.default(0.6),
    }),
    ai_routing: z.object({
      high_confidence_threshold: ProbabilitySchema.default(0.8),
      ai_required_threshold: ProbabilitySchema.default(0.4),
    }),
  }),

  // Basic performance settings
  performance: z.object({
    parallel_processing: z.boolean().default(true),
    batch_size: PositiveIntegerSchema.default(50),
    timeout_ms: PositiveIntegerSchema.default(60000),
  }).default({}),
});

// Type inference
export type ProcessingConfigTuning = z.infer<typeof ProcessingConfigTuningSchema>;
export type BasicProcessingConfig = z.infer<typeof BasicProcessingConfigSchema>;
export type HardAssertionTuning = z.infer<typeof HardAssertionTuningSchema>;
export type StrongIndicatorTuning = z.infer<typeof StrongIndicatorTuningSchema>;
export type RuleScoringTuning = z.infer<typeof RuleScoringTuningSchema>;
export type AttributeDetectionTuning = z.infer<typeof AttributeDetectionTuningSchema>;
export type AttributeInfluenceTuning = z.infer<typeof AttributeInfluenceTuningSchema>;
export type DisambiguationTuning = z.infer<typeof DisambiguationTuningSchema>;
export type MultiLabelTuning = z.infer<typeof MultiLabelTuningSchema>;
export type AIRoutingTuning = z.infer<typeof AIRoutingTuningSchema>;
export type AuditTrailTuning = z.infer<typeof AuditTrailTuningSchema>;
export type PerformanceTuning = z.infer<typeof PerformanceTuningSchema>;

// Validation helper functions
export const validateProcessingConfigTuning = (config: unknown): ProcessingConfigTuning => {
  return ProcessingConfigTuningSchema.parse(config);
};

export const validateBasicProcessingConfig = (config: unknown): BasicProcessingConfig => {
  return BasicProcessingConfigSchema.parse(config);
};

// Tuning parameter validation helpers
export const validateHardAssertionTuning = (tuning: unknown): HardAssertionTuning => {
  return HardAssertionTuningSchema.parse(tuning);
};

export const validateRuleScoringTuning = (tuning: unknown): RuleScoringTuning => {
  return RuleScoringTuningSchema.parse(tuning);
};

export const validateAttributeInfluenceTuning = (tuning: unknown): AttributeInfluenceTuning => {
  return AttributeInfluenceTuningSchema.parse(tuning);
};

export const validatePerformanceTuning = (tuning: unknown): PerformanceTuning => {
  return PerformanceTuningSchema.parse(tuning);
};

// Configuration validation utilities
export const isValidProcessingConfig = (config: unknown): boolean => {
  try {
    ProcessingConfigTuningSchema.parse(config);
    return true;
  } catch {
    return false;
  }
};

export const getProcessingConfigErrors = (config: unknown): string[] => {
  try {
    ProcessingConfigTuningSchema.parse(config);
    return [];
  } catch (error) {
    if (error instanceof z.ZodError) {
      return error.errors.map(err => `${err.path.join('.')}: ${err.message}`);
    }
    return ['Unknown validation error'];
  }
};

// Default configurations for different use cases
export const getDefaultProductionConfig = (): Partial<ProcessingConfigTuning> => ({
  performance_tuning: {
    parallel_processing_enabled: true,
    max_parallel_emails: 20,
    email_batch_size: 100,
    enable_caching: true,
    total_processing_timeout_ms: 45000,
  },
  monitoring: {
    enable_metrics_collection: true,
    detailed_timing: false,
    memory_tracking: true,
    error_tracking: true,
  },
});

export const getDefaultDevelopmentConfig = (): Partial<ProcessingConfigTuning> => ({
  performance_tuning: {
    parallel_processing_enabled: true,
    max_parallel_emails: 5,
    email_batch_size: 10,
    enable_caching: false,
    total_processing_timeout_ms: 120000,
  },
  monitoring: {
    enable_metrics_collection: true,
    detailed_timing: true,
    memory_tracking: true,
    error_tracking: true,
  },
  strict_validation: true,
  allow_experimental_features: true,
});

export const getDefaultTestingConfig = (): Partial<ProcessingConfigTuning> => ({
  performance_tuning: {
    parallel_processing_enabled: false,
    max_parallel_emails: 1,
    email_batch_size: 5,
    enable_caching: false,
    total_processing_timeout_ms: 180000,
  },
  monitoring: {
    enable_metrics_collection: false,
    detailed_timing: true,
    memory_tracking: false,
    error_tracking: true,
  },
  strict_validation: true,
  allow_experimental_features: true,
  compatibility_mode: 'permissive',
});

