   213→  /**
   214→   * Validate domain sources configuration
   215→   */
   216→  async validateDomainSources(
   217→    config: Record<string, string[]> | unknown,
   218→    options: ValidationOptions = {}
   219→  ): Promise<ValidationResult> {
   220→    const startTime = Date.now();
   221→    const errors: ValidationError[] = [];
   222→    const warnings: ValidationWarning[] = [];
   223→
   224→    if (!config || typeof config !== 'object') {
   225→      errors.push({
   226→        code: 'INVALID_DOMAIN_SOURCES_TYPE',
   227→        message: 'Domain sources must be an object',
   228→        path: 'root',
   229→        severity: 'error',
   230→        category: 'schema',
   231→      });
   232→      return this.buildValidationResult(startTime, errors, warnings, 0, 0, 0);
   233→    }
   234→
   235→    const domainSources = config as Record<string, string[]>;
   236→
   237→    // Validate domain groups
   238→    for (const [groupName, domains] of Object.entries(domainSources)) {
   239→      if (!Array.isArray(domains)) {
   240→        errors.push({
   241→          code: 'INVALID_DOMAIN_GROUP_TYPE',
   242→          message: `Domain group "${groupName}" must be an array`,
   243→          path: groupName,
   244→          severity: 'error',
   245→          category: 'schema',
   246→        });
   247→        continue;
   248→      }
   249→
   250→      // Validate individual domains
   251→      for (let i = 0; i < domains.length; i++) {
   252→        const domain = domains[i];
   253→        if (typeof domain !== 'string') {
   254→          errors.push({
   255→            code: 'INVALID_DOMAIN_TYPE',
   256→            message: `Domain at index ${i} in group "${groupName}" must be a string`,
   257→            path: `${groupName}[${i}]`,
   258→            severity: 'error',
   259→            category: 'schema',
   260→          });
   261→          continue;
   262→        }
   263→
   264→        // Validate domain format
   265→        if (!/^[a-zA-Z0-9.-]+\.[a-zA-Z]{2,}$/.test(domain)) {
   266→          errors.push({
   267→            code: 'INVALID_DOMAIN_FORMAT',
   268→            message: `Invalid domain format: "${domain}" in group "${groupName}"`,
   269→            path: `${groupName}[${i}]`,
   270→            severity: 'error',
   271→            category: 'logic',
   272→            suggestion: 'Use valid domain format like "example.com"',
   273→          });
   274→        }
   275→      }
   276→
   277→      // Check for duplicate domains within group
   278→      const uniqueDomains = new Set(domains);
   279→      if (uniqueDomains.size !== domains.length) {
   280→        warnings.push({
   281→          code: 'DUPLICATE_DOMAINS_IN_GROUP',
   282→          message: `Group "${groupName}" contains duplicate domains`,
   283→          path: groupName,
   284→          impact: 'low',
   285→          recommendation: 'Remove duplicate domains to improve configuration clarity',
   286→        });
   287→      }
   288→    }
   289→
   290→    // Check for domains appearing in multiple groups
   291→    const allDomains = new Map<string, string[]>();
   292→    for (const [groupName, domains] of Object.entries(domainSources)) {
   293→      for (const domain of domains) {
   294→        if (!allDomains.has(domain)) {
   295→          allDomains.set(domain, []);
   296→        }
   297→        allDomains.get(domain)!.push(groupName);
   298→      }
   299→    }
   300→
   301→    for (const [domain, groups] of allDomains) {
   302→      if (groups.length > 1) {
   303→        warnings.push({
   304→          code: 'DOMAIN_IN_MULTIPLE_GROUPS',
   305→          message: `Domain "${domain}" appears in multiple groups: ${groups.join(', ')}`,
   306→          path: 'cross-reference',
   307→          impact: 'medium',
   308→          recommendation: 'Consider if this domain should only be in one group for clarity',
   309→        });
   310→      }
   311→    }
   312→
   313→    return this.buildValidationResult(startTime, errors, warnings, 0, 0, allDomains.size);
   314→  }
