   397→  private async validateCrossReferences(config: CategoryConfiguration): Promise<{
   398→    errors: ValidationError[];
   399→    warnings: ValidationWarning[];
   400→    totalChecks: number;
   401→  }> {
   402→    const errors: ValidationError[] = [];
   403→    const warnings: ValidationWarning[] = [];
   404→    let totalChecks = 0;
   405→
   406→    // Get defined attributes
   407→    const definedAttributes = new Set(Object.keys(config.processing_config.attributes.schema));
   408→
   409→    // Check attribute references in relevance matrix
   410→    for (const [categoryName, categoryConfig] of Object.entries(config.processing_config.attribute_relevance)) {
   411→      if (categoryName === '_roles_legend') continue;
   412→
   413→      totalChecks++;
   414→
   415→      if (categoryConfig.category_roles) {
   416→        for (const attributeName of Object.keys(categoryConfig.category_roles)) {
   417→          totalChecks++;
   418→          if (!definedAttributes.has(attributeName)) {
   419→            errors.push({
   420→              code: 'UNDEFINED_ATTRIBUTE_REFERENCE',
   421→              message: `Category "${categoryName}" references undefined attribute: "${attributeName}"`,
   422→              path: `attribute_relevance.${categoryName}.category_roles.${attributeName}`,
   423→              severity: 'error',
   424→              category: 'reference',
   425→              suggestion: `Define attribute "${attributeName}" in attributes.schema or remove the reference`,
   426→            });
   427→          }
   428→        }
   429→      }
   430→    }
   431→
   432→    // Check for orphaned attributes (defined but not used)
   433→    const usedAttributes = new Set<string>();
   434→    for (const [categoryName, categoryConfig] of Object.entries(config.processing_config.attribute_relevance)) {
   435→      if (categoryName === '_roles_legend') continue;
   436→      if (categoryConfig.category_roles) {
   437→        Object.keys(categoryConfig.category_roles).forEach(attr => usedAttributes.add(attr));
   438→      }
   439→    }
   440→
   441→    for (const attributeName of definedAttributes) {
   442→      totalChecks++;
   443→      if (!usedAttributes.has(attributeName)) {
   444→        warnings.push({
   445→          code: 'ORPHANED_ATTRIBUTE',
   446→          message: `Attribute "${attributeName}" is defined but not used in any category`,
   447→          path: `attributes.schema.${attributeName}`,
   448→          impact: 'low',
   449→          recommendation: 'Consider removing unused attributes or adding them to relevance matrix',
   450→        });
   451→      }
   452→    }
   453→
   454→    return { errors, warnings, totalChecks };
   455→  }
