   259→      return result;
   260→    } catch (error) {
   261→      this.emit('configError', { type: 'processing', filepath, error });
   262→      throw new Error(`Failed to load processing configuration from ${filepath}: ${error.message}`);
   263→    }
   264→  }
   265→
   266→  /**
   267→   * Load domain sources configuration
   268→   */
   269→  async loadDomainSources(
   270→    filename: string = 'domain-sources.json'
   271→  ): Promise<ConfigLoadResult<Record<string, string[]>>> {
   272→    const filepath = path.join(this.configDir, filename);
   273→
   274→    try {
   275→      const startTime = Date.now();
   276→
   277→      // Check cache first
   278→      const cached = this.getCachedConfig<Record<string, string[]>>(filepath);
   279→      if (cached) {
   280→        return cached;
   281→      }
   282→
   283→      // Load and parse configuration
   284→      const fileContent = await fs.readFile(filepath, 'utf-8');
   285→      const hash = this.calculateHash(fileContent);
   286→      const stats = await fs.stat(filepath);
   287→
   288→      let config: Record<string, string[]>;
   289→      try {
   290→        config = JSON.parse(fileContent);
   291→      } catch (parseError) {
   292→        throw new Error(`Failed to parse JSON in ${filepath}: ${parseError.message}`);
   293→      }
   294→
   295→      // Basic validation for domain sources
   296→      const validationErrors = this.validateDomainSources(config);
   297→      const validationPassed = validationErrors.length === 0;
   298→
   299→      const result: ConfigLoadResult<Record<string, string[]>> = {
   300→        config,
   301→        hash,
   302→        lastModified: stats.mtime,
   303→        validationPassed,
   304→        validationErrors,
   305→        loadTime: Date.now() - startTime,
   306→      };
   307→
   308→      // Cache the result
   309→      this.setCachedConfig(filepath, result);
   310→      this.lastHashes.set(filepath, hash);
   311→
   312→      // Set up hot-reload if enabled
   313→      if (this.enableHotReload && !this.watchers.has(filepath)) {
   314→        await this.setupHotReload(filepath, 'domains');
   315→      }
   316→
   317→      this.emit('configLoaded', { type: 'domains', filepath, result });
   318→
   319→      return result;
   320→    } catch (error) {
   321→      this.emit('configError', { type: 'domains', filepath, error });
   322→      throw new Error(`Failed to load domain sources from ${filepath}: ${error.message}`);
   323→    }
   324→  }
