   326→  /**
   327→   * Reload a specific configuration file
   328→   */
   329→  async reloadConfiguration(filepath: string): Promise<void> {
   330→    // Clear cache for this file
   331→    this.configCache.delete(filepath);
   332→
   333→    // Determine config type and reload
   334→    const filename = path.basename(filepath);
   335→
   336→    if (filename.includes('email-categorizer-config') || filename.includes('category')) {
   337→      await this.loadCategoryConfiguration(filename);
   338→    } else if (filename.includes('processing-config') || filename.includes('processing')) {
   339→      await this.loadProcessingConfiguration(filename);
   340→    } else if (filename.includes('domain-sources') || filename.includes('domain')) {
   341→      await this.loadDomainSources(filename);
   342→    } else {
   343→      throw new Error(`Unknown configuration type for file: ${filename}`);
   344→    }
   345→  }
