   354→  /**
   355→   * Check if configuration has changed
   356→   */
   357→  async hasConfigurationChanged(filepath: string): Promise<boolean> {
   358→    try {
   359→      const content = await fs.readFile(filepath, 'utf-8');
   360→      const currentHash = this.calculateHash(content);
   361→      const lastHash = this.lastHashes.get(filepath);
   362→      return currentHash !== lastHash;
   363→    } catch {
