   371→  cleanup(): void {
   372→    for (const [filepath, watcher] of this.watchers) {
   373→      try {
   374→        watcher.close();
   375→      } catch (error) {
   376→        console.warn(`Failed to close watcher for ${filepath}:`, error);
   377→      }
   378→    }
   379→    this.watchers.clear();
   380→    this.configCache.clear();
   381→    this.lastHashes.clear();
