   383→
   384→  // Private methods
   385→
   386→  private getCachedConfig<T>(filepath: string): ConfigLoadResult<T> | undefined {
   387→    const cached = this.configCache.get(filepath);
   388→    if (!cached) return undefined;
   389→
   390→    const age = Date.now() - cached.loadTime;
   391→    if (age > this.cacheTtlMs) {
   392→      this.configCache.delete(filepath);
   393→      return undefined;
   394→    }
   395→
   396→    return cached as ConfigLoadResult<T>;
