   407→  private async setupHotReload(filepath: string, configType: string): Promise<void> {
   408→    try {
   409→      const watcher = watch(filepath, { persistent: false });
   410→
   411→      watcher.on('change', async () => {
   412→        try {
   413→          if (await this.hasConfigurationChanged(filepath)) {
   414→            this.emit('configChanging', { type: configType, filepath });
   415→            await this.reloadConfiguration(filepath);
   416→            this.emit('configChanged', { type: configType, filepath });
   417→          }
   418→        } catch (error) {
   419→          this.emit('configError', { type: configType, filepath, error });
   420→        }
   421→      });
   422→
   423→      watcher.on('error', (error) => {
   424→        this.emit('configError', { type: configType, filepath, error });
   425→      });
   426→
   427→      this.watchers.set(filepath, watcher);
   428→    } catch (error) {
   429→      console.warn(`Failed to setup hot-reload for ${filepath}:`, error);
   430→    }
   431→  }
