   433→  private async createBackup(filepath: string, hash: string): Promise<void> {
   434→    try {
   435→      const backupDir = path.join(path.dirname(filepath), '.backups');
   436→      await fs.mkdir(backupDir, { recursive: true });
   437→
   438→      const filename = path.basename(filepath);
   439→      const timestamp = new Date().toISOString().replace(/[:.]/g, '-');
   440→      const backupPath = path.join(backupDir, `${filename}.${timestamp}.${hash.slice(0, 8)}.backup`);
   441→
   442→      await fs.copyFile(filepath, backupPath);
   443→
   444→      // Keep only last 10 backups
