   459→  private async compileConfigurationRules(config: CategoryConfiguration): Promise<CompiledRule[]> {
   460→    const startTime = Date.now();
   461→    const compiledRules: CompiledRule[] = [];
   462→
   463→    for (const [categoryName, category] of Object.entries(config.processing_config.top_level_categories)) {
   464→      for (const [subtypeName, subtype] of Object.entries(category.subtypes)) {
   465→        if (subtype.rule_based_classification) {
   466→          for (const [tier, rules] of Object.entries(subtype.rule_based_classification)) {
   467→            if (rules) {
   468→              for (const rule of rules) {
   469→                try {
   470→                  let pattern: RegExp;
   471→
   472→                  switch (rule.operation) {
   473→                    case 'contains_any':
   474→                      pattern = new RegExp(
   475→                        rule.values?.map((v) => v.replace(/[.*+?^${}()|[\\]\\\\]/g, '\\\\$&')).join('|') || '',
   476→                        'i'
   477→                      );
   478→                      break;
   479→                    case 'starts_with':
   480→                      pattern = new RegExp(
   481→                        '^(' +
   482→                          (rule.values?.map((v) => v.replace(/[.*+?^${}()|[\\]\\\\]/g, '\\\\$&')).join('|') || '') +
   483→                          ')',
   484→                        'i'
   485→                      );
   486→                      break;
   487→                    case 'ends_with':
   488→                      pattern = new RegExp(
   489→                        '(' +
   490→                          (rule.values?.map((v) => v.replace(/[.*+?^${}()|[\\]\\\\]/g, '\\\\$&')).join('|') || '') +
   491→                          ')$',
   492→                        'i'
   493→                      );
   494→                      break;
   495→                    case 'regex_any':
   496→                      pattern = new RegExp(rule.values?.join('|') || '', 'i');
   497→                      break;
   498→                    default:
   499→                      continue; // Skip unknown operations
   500→                  }
   501→
   502→                  compiledRules.push({
   503→                    category: categoryName,
   504→                    subtype: subtypeName,
   505→                    tier: tier as 'high' | 'medium' | 'low',
   506→                    pattern,
   507→                    weight: rule.weight,
   508→                    parallel_safe: true, // Assume parallel safe unless marked otherwise
   509→                  });
   510→                } catch (error) {
   511→                  console.warn(`Failed to compile rule for ${categoryName}.${subtypeName}.${tier}:`, error);
   512→                }
   513→              }
   514→            }
   515→          }
   516→        }
   517→      }
   518→    }
   519→
   520→    // Update performance metrics
   521→    if (!config.performanceMetrics) {
   522→      config.performanceMetrics = {};
   523→    }
   524→    config.performanceMetrics.rule_compilation_time_ms = Date.now() - startTime;
   525→    config.performanceMetrics.total_rules = compiledRules.length;
   526→    config.performanceMetrics.parallel_compatible_rules = compiledRules.filter((r) => r.parallel_safe).length;
   527→
   528→    return compiledRules;
   529→  }
