declare interface ConfigurationLoader {
  on<U extends keyof ConfigEvents>(event: U, listener: (data: ConfigEvents[U]) => void): this;
  emit<U extends keyof ConfigEvents>(event: U, data: ConfigEvents[U]): boolean;
}

