      // Performance metrics
      if (!validatedConfig.performanceMetrics) {
        validatedConfig.performanceMetrics = {};
      }
      validatedConfig.performanceMetrics.last_validation_time_ms = Date.now() - startTime;

      const result: ConfigLoadResult<CategoryConfiguration> = {
        config: validatedConfig,
        hash,
        lastModified: stats.mtime,
        validationPassed,
        validationErrors,
        loadTime: Date.now() - startTime,
      };

      // Cache the result
      this.setCachedConfig(filepath, result);
      this.lastHashes.set(filepath, hash);

      // Set up hot-reload if enabled
      if (this.enableHotReload && !this.watchers.has(filepath)) {
        await this.setupHotReload(filepath, 'category');
      }

      // Create backup if enabled
      if (this.backupOnChange && validationPassed) {
        await this.createBackup(filepath, hash);
      }

      this.emit('configLoaded', { type: 'category', filepath, result });

      return result;
    } catch (error) {
      this.emit('configError', { type: 'category', filepath, error: error as Error });
      throw new Error(
        `Failed to load category configuration from ${filepath}: ${error instanceof Error ? error.message : String(error)}`
      );
    }
  }

  /**
   * Load processing configuration with validation
   */
  async loadProcessingConfiguration(
    filename: string = 'processing-config.json'
  ): Promise<ConfigLoadResult<ProcessingConfigTuning>> {
    const filepath = join(this.configDir, filename);

    try {
      const startTime = Date.now();

      // Check cache first
      const cached = this.getCachedConfig<ProcessingConfigTuning>(filepath);
      if (cached) {
        return cached;
      }

      // Load and parse configuration
      const fileContent = await fs.readFile(filepath, 'utf-8');
      const hash = this.calculateHash(fileContent);
      const stats = await fs.stat(filepath);

      let config: any;
      try {
        config = JSON.parse(fileContent);
      } catch (parseError) {
        throw new Error(
          `Failed to parse JSON in ${filepath}: ${parseError instanceof Error ? parseError.message : String(parseError)}`
        );
      }

      // Validate configuration
      let validationPassed = true;
      let validationErrors: string[] = [];
      let validatedConfig: ProcessingConfigTuning;

      if (this.validateOnLoad) {
        try {
          validatedConfig = validateProcessingConfigTuning(config);

          // Additional custom validation
          validationErrors = await this.validateProcessingConfigurationCustom(validatedConfig);
          validationPassed = validationErrors.length === 0;
        } catch (error) {
          validationPassed = false;
          validationErrors = getProcessingConfigErrors(config);
          validatedConfig = config; // Use unvalidated config for error reporting
        }
      } else {
        validatedConfig = config;
      }

      const result: ConfigLoadResult<ProcessingConfigTuning> = {
        config: validatedConfig,
        hash,
        lastModified: stats.mtime,
        validationPassed,
        validationErrors,
        loadTime: Date.now() - startTime,
      };

      // Cache the result
      this.setCachedConfig(filepath, result);
      this.lastHashes.set(filepath, hash);

      // Set up hot-reload if enabled
      if (this.enableHotReload && !this.watchers.has(filepath)) {
        await this.setupHotReload(filepath, 'processing');
      }

      this.emit('configLoaded', { type: 'processing', filepath, result });

      return result;
    } catch (error) {
      this.emit('configError', { type: 'processing', filepath, error: error as Error });
      throw new Error(
        `Failed to load processing configuration from ${filepath}: ${error instanceof Error ? error.message : String(error)}`
      );
    }
  }

  /**
   * Load domain sources configuration
   */
  async loadDomainSources(
    filename: string = 'domain-sources.json'
  ): Promise<ConfigLoadResult<Record<string, string[]>>> {
    const filepath = join(this.configDir, filename);

    try {
      const startTime = Date.now();

      // Check cache first
      const cached = this.getCachedConfig<Record<string, string[]>>(filepath);
      if (cached) {
        return cached;
      }

      // Load and parse configuration
      const fileContent = await fs.readFile(filepath, 'utf-8');
      const hash = this.calculateHash(fileContent);
      const stats = await fs.stat(filepath);

      let config: Record<string, string[]>;
      try {
        config = JSON.parse(fileContent);
      } catch (parseError) {
        throw new Error(
          `Failed to parse JSON in ${filepath}: ${parseError instanceof Error ? parseError.message : String(parseError)}`
        );
      }

      // Basic validation for domain sources
      const validationErrors = this.validateDomainSources(config);
      const validationPassed = validationErrors.length === 0;

      const result: ConfigLoadResult<Record<string, string[]>> = {
        config,
        hash,
        lastModified: stats.mtime,
        validationPassed,
        validationErrors,
        loadTime: Date.now() - startTime,
      };

      // Cache the result
      this.setCachedConfig(filepath, result);
      this.lastHashes.set(filepath, hash);

      // Set up hot-reload if enabled
      if (this.enableHotReload && !this.watchers.has(filepath)) {
        await this.setupHotReload(filepath, 'domains');
      }

      this.emit('configLoaded', { type: 'domains', filepath, result });

      return result;
    } catch (error) {
      this.emit('configError', { type: 'domains', filepath, error: error as Error });
      throw new Error(
        `Failed to load domain sources from ${filepath}: ${error instanceof Error ? error.message : String(error)}`
      );
    }
  }

  /**
   * Reload a specific configuration file
   */
  async reloadConfiguration(filepath: string): Promise<void> {
    // Clear cache for this file
    this.configCache.delete(filepath);

    // Determine config type and reload
    const filename = basename(filepath);

    if (filename.includes('email-categorizer-config') || filename.includes('category')) {
      await this.loadCategoryConfiguration(filename);
    } else if (filename.includes('processing-config') || filename.includes('processing')) {
      await this.loadProcessingConfiguration(filename);
    } else if (filename.includes('domain-sources') || filename.includes('domain')) {
      await this.loadDomainSources(filename);
    } else {
      throw new Error(`Unknown configuration type for file: ${filename}`);
    }
  }

  /**
   * Get configuration hash for change detection
   */
  getConfigurationHash(filepath: string): string | undefined {
    return this.lastHashes.get(filepath);
  }

  /**
   * Check if configuration has changed
   */
  async hasConfigurationChanged(filepath: string): Promise<boolean> {
    try {
      const content = await fs.readFile(filepath, 'utf-8');
      const currentHash = this.calculateHash(content);
      const lastHash = this.lastHashes.get(filepath);
      return currentHash !== lastHash;
    } catch {
      return true; // Assume changed if can't read
    }
  }

  /**
   * Cleanup watchers and resources
   */
  cleanup(): void {
    for (const [filepath, watcher] of this.watchers) {
      try {
        watcher.close();
      } catch (error) {
        console.warn(`Failed to close watcher for ${filepath}:`, error);
      }
    }
    this.watchers.clear();
    this.configCache.clear();
    this.lastHashes.clear();
  }

  // Private methods

  private getCachedConfig<T>(filepath: string): ConfigLoadResult<T> | undefined {
    const cached = this.configCache.get(filepath);
    if (!cached) return undefined;

    const age = Date.now() - cached.loadTime;
    if (age > this.cacheTtlMs) {
      this.configCache.delete(filepath);
      return undefined;
    }

    return cached as ConfigLoadResult<T>;
  }

  private setCachedConfig<T>(filepath: string, result: ConfigLoadResult<T>): void {
    this.configCache.set(filepath, result);
  }

  private calculateHash(content: string): string {
    return createHash('sha256').update(content).digest('hex');
  }

  private async setupHotReload(filepath: string, configType: string): Promise<void> {
    try {
      const watcher = watch(filepath, { persistent: false });

      watcher.on('change', async () => {
        try {
          if (await this.hasConfigurationChanged(filepath)) {
            this.emit('configChanging', { type: configType, filepath });
            await this.reloadConfiguration(filepath);
            this.emit('configChanged', { type: configType, filepath });
          }
        } catch (error) {
          this.emit('configError', { type: configType, filepath, error: error as Error });
        }
      });

      watcher.on('error', (error) => {
        this.emit('configError', { type: configType, filepath, error });
      });

      this.watchers.set(filepath, watcher);
    } catch (error) {
      console.warn(`Failed to setup hot-reload for ${filepath}:`, error);
    }
  }

  private async createBackup(filepath: string, hash: string): Promise<void> {
    try {
      const backupDir = join(dirname(filepath), '.backups');
      await fs.mkdir(backupDir, { recursive: true });

      const filename = basename(filepath);
      const timestamp = new Date().toISOString().replace(/[:.]/g, '-');
      const backupPath = join(backupDir, `${filename}.${timestamp}.${hash.slice(0, 8)}.backup`);

      await fs.copyFile(filepath, backupPath);

      // Keep only last 10 backups
      const backups = await fs.readdir(backupDir);
      const fileBackups = backups
        .filter((f) => f.startsWith(filename))
        .sort()
        .reverse();

      for (const backup of fileBackups.slice(10)) {
        await fs.unlink(join(backupDir, backup));
      }
    } catch (error) {
      console.warn(`Failed to create backup for ${filepath}:`, error);
    }
  }

  private async compileConfigurationRules(config: CategoryConfiguration): Promise<CompiledRule[]> {
    const startTime = Date.now();
    const compiledRules: CompiledRule[] = [];

    for (const [categoryName, category] of Object.entries(config.processing_config.top_level_categories)) {
      for (const [subtypeName, subtype] of Object.entries(category.subtypes)) {
        if (subtype.rule_based_classification) {
          for (const [tier, rules] of Object.entries(subtype.rule_based_classification)) {
            if (rules) {
              for (const rule of rules) {
                try {
                  let pattern: RegExp;

                  switch (rule.operation) {
                    case 'contains_any':
                      pattern = new RegExp(
                        rule.values?.map((v) => v.replace(/[.*+?^${}()|[\\]\\\\]/g, '\\\\$&')).join('|') || '',
                        'i'
                      );
                      break;
                    case 'starts_with':
                      pattern = new RegExp(
                        '^(' +
                          (rule.values?.map((v) => v.replace(/[.*+?^${}()|[\\]\\\\]/g, '\\\\$&')).join('|') || '') +
                          ')',
                        'i'
                      );
                      break;
                    case 'ends_with':
                      pattern = new RegExp(
                        '(' +
                          (rule.values?.map((v) => v.replace(/[.*+?^${}()|[\\]\\\\]/g, '\\\\$&')).join('|') || '') +
                          ')$',
                        'i'
                      );
                      break;
                    case 'regex_any':
                      pattern = new RegExp(rule.values?.join('|') || '', 'i');
                      break;
                    default:
                      continue; // Skip unknown operations
                  }

                  compiledRules.push({
                    category: categoryName,
                    subtype: subtypeName,
                    tier: tier as 'high' | 'medium' | 'low',
                    pattern,
                    weight: rule.weight,
                    parallel_safe: true, // Assume parallel safe unless marked otherwise
                  });
                } catch (error) {
                  console.warn(`Failed to compile rule for ${categoryName}.${subtypeName}.${tier}:`, error);
                }
              }
            }
          }
        }
      }
    }

    // Update performance metrics
    if (!config.performanceMetrics) {
      config.performanceMetrics = {};
    }
    config.performanceMetrics.rule_compilation_time_ms = Date.now() - startTime;
    config.performanceMetrics.total_rules = compiledRules.length;
    config.performanceMetrics.parallel_compatible_rules = compiledRules.filter((r) => r.parallel_safe).length;

    return compiledRules;
  }

  private async computeAttributeMatrix(config: CategoryConfiguration): Promise<AttributeInfluenceMatrix> {
    const startTime = Date.now();
    const matrix: AttributeInfluenceMatrix = {};

    // Build attribute influence matrix from attribute_relevance configuration
    const attributeRelevance = config.processing_config.attribute_relevance;

    for (const [categoryName, categoryConfig] of Object.entries(attributeRelevance)) {
      if (categoryName === '_roles_legend') continue;

      matrix[categoryName] = {};

      // Process category-level roles
      if (categoryConfig.category_roles) {
        for (const [attributeName, role] of Object.entries(categoryConfig.category_roles)) {
          matrix[categoryName][attributeName] = {
            role: role,
            bonus: this.getRoleBonus(role),
            cap: this.getRoleCap(role),
          };
        }
      }

      // Process subtype-specific roles
      if (categoryConfig.subtypes) {
        for (const [subtypeName, subtypeConfig] of Object.entries(categoryConfig.subtypes)) {
          const subtypeKey = `${categoryName}.${subtypeName}`;
          matrix[subtypeKey] = {};

          for (const [attributeName, role] of Object.entries(subtypeConfig.roles)) {
            matrix[subtypeKey][attributeName] = {
              role: role,
              bonus: this.getRoleBonus(role),
              cap: this.getRoleCap(role),
            };
          }
        }
      }
    }

    // Update performance metrics
    if (!config.performanceMetrics) {
      config.performanceMetrics = {};
    }
    config.performanceMetrics.matrix_computation_time_ms = Date.now() - startTime;

    return matrix;
  }

  private getRoleBonus(role: string): number {
    switch (role) {
      case 'CORE':
        return 0.4;
      case 'PRIMARY_BOOST':
        return 0.3;
      case 'SECONDARY_BOOST':
        return 0.2;
      case 'DISAMBIGUATOR':
        return 0.15;
      case 'FILTER':
        return -0.1;
      default:
        return 0;
    }
  }

  private getRoleCap(role: string): number {
    switch (role) {
      case 'CORE':
        return 0.5;
      case 'PRIMARY_BOOST':
        return 0.4;
      case 'SECONDARY_BOOST':
        return 0.3;
      case 'DISAMBIGUATOR':
        return 0.2;
      case 'FILTER':
        return 0.1;
      default:
        return 0.1;
    }
  }

  private async validateCategoryConfigurationCustom(config: CategoryConfiguration): Promise<string[]> {
    const errors: string[] = [];

    // Check that all referenced attributes exist
    const definedAttributes = new Set(Object.keys(config.processing_config.attributes.schema));

    // Check attribute references in relevance matrix
    for (const [categoryName, categoryConfig] of Object.entries(config.processing_config.attribute_relevance)) {
      if (categoryName === '_roles_legend') continue;

      if (categoryConfig.category_roles) {
        for (const attributeName of Object.keys(categoryConfig.category_roles)) {
          if (!definedAttributes.has(attributeName)) {
            errors.push(`Category ${categoryName} references undefined attribute: ${attributeName}`);
          }
        }
      }
    }

    // Check domain references
    for (const [categoryName, signals] of Object.entries(config.processing_config.category_signals)) {
      if (signals.hard_assertions?.from_domains_ref || signals.strong_indicators?.from_domains_ref) {
        // These will be validated against domain-sources.json at runtime
      }
    }

    return errors;
  }

  private async validateProcessingConfigurationCustom(config: ProcessingConfigTuning): Promise<string[]> {
    const errors: string[] = [];

    // Validate performance settings consistency
    if (config.performance_tuning) {
      const perf = config.performance_tuning;

      if (perf.max_parallel_emails && perf.email_batch_size) {
        if (perf.max_parallel_emails > perf.email_batch_size) {
          errors.push('max_parallel_emails should not exceed email_batch_size');
        }
      }

      if (perf.total_processing_timeout_ms && perf.stage_timeout_ms) {
        if (perf.stage_timeout_ms >= perf.total_processing_timeout_ms) {
          errors.push('stage_timeout_ms should be less than total_processing_timeout_ms');
        }
      }
    }

    // Validate AI routing settings
    if (config.ai_routing_tuning) {
      const ai = config.ai_routing_tuning;

      if (ai.high_confidence_threshold <= ai.ai_required_threshold) {
        errors.push('high_confidence_threshold should be greater than ai_required_threshold');
      }
    }

    return errors;
  }

  private validateDomainSources(config: Record<string, string[]>): string[] {
    const errors: string[] = [];

    for (const [groupName, domains] of Object.entries(config)) {
      if (!Array.isArray(domains)) {
        errors.push(`Domain group ${groupName} must be an array of strings`);
        continue;
      }

      for (const domain of domains) {
        if (typeof domain !== 'string') {
          errors.push(`Domain group ${groupName} contains non-string domain: ${domain}`);
        } else if (!/^[a-zA-Z0-9.-]+\\.[a-zA-Z]{2,}$/.test(domain)) {
          errors.push(`Domain group ${groupName} contains invalid domain format: ${domain}`);
        }
      }
    }

    return errors;
  }
}

// Default instance for convenience
export const configLoader = new ConfigurationLoader();

// Event type definitions for TypeScript
export interface ConfigEvents {
  configLoaded: { type: string; filepath: string; result: ConfigLoadResult<any> };
  configChanged: { type: string; filepath: string };
  configChanging: { type: string; filepath: string };
  configError: { type: string; filepath: string; error: Error };
}

declare interface ConfigurationLoader {
  on<U extends keyof ConfigEvents>(event: U, listener: (data: ConfigEvents[U]) => void): this;
  emit<U extends keyof ConfigEvents>(event: U, data: ConfigEvents[U]): boolean;
}

