import {
  CategoryConfiguration,
  ProcessingConfig,
  CategorySignals,
  validateCategoryConfiguration,
  validateProcessingConfig,
  getValidationErrors,
} from './category-config-schema.js';
import {
  ProcessingConfigTuning,
  validateProcessingConfigTuning,
  getProcessingConfigErrors,
} from './processing-config-schema.js';
import { ConfigurationLoader, ConfigLoadResult } from './config-loader.js';

/**
 * Configuration validation service
 * Provides comprehensive validation for all configuration types
 */

export interface ValidationResult {
  isValid: boolean;
  errors: ValidationError[];
  warnings: ValidationWarning[];
  performance: ValidationPerformance;
  summary: ValidationSummary;
}

export interface ValidationError {
  code: string;
  message: string;
  path: string;
  severity: 'error' | 'warning';
  category: 'schema' | 'logic' | 'reference' | 'performance' | 'security';
  suggestion?: string;
}

export interface ValidationWarning {
  code: string;
  message: string;
  path: string;
  impact: 'low' | 'medium' | 'high';
  recommendation: string;
}

export interface ValidationPerformance {
  validationTimeMs: number;
  rulesChecked: number;
  attributesValidated: number;
  crossReferencesChecked: number;
}

export interface ValidationSummary {
  totalErrors: number;
  totalWarnings: number;
  criticalIssues: number;
  configurationHealth: 'excellent' | 'good' | 'fair' | 'poor';
  recommendedActions: string[];
}

export interface CrossReferenceCheck {
  attributeReferences: string[];
  domainReferences: string[];
  categoryReferences: string[];
  orphanedReferences: string[];
}

export interface ValidationOptions {
  skipCrossReferences?: boolean;
  skipPerformanceChecks?: boolean;
  skipSecurityChecks?: boolean;
  skipQualityChecks?: boolean;
  strictMode?: boolean;
}

export class ConfigurationValidator {
  private configLoader: ConfigurationLoader;

  constructor(configLoader?: ConfigurationLoader) {
    this.configLoader = configLoader || new ConfigurationLoader();
  }

  /**
   * Validate category configuration with comprehensive checks
   */
  async validateCategoryConfiguration(
    config: CategoryConfiguration | unknown,
    options: ValidationOptions = {}
  ): Promise<ValidationResult> {
    const startTime = Date.now();
    const errors: ValidationError[] = [];
    const warnings: ValidationWarning[] = [];

    let validatedConfig: CategoryConfiguration;

    // Schema validation
    try {
      if (typeof config === 'object' && config !== null && 'processing_config' in config) {
        validatedConfig = config as CategoryConfiguration;
        validateCategoryConfiguration(config);
      } else {
        validatedConfig = validateCategoryConfiguration(config);
      }
    } catch (error) {
      const schemaErrors = getValidationErrors(config);
      errors.push(
        ...schemaErrors.map((err) => ({
          code: 'SCHEMA_VALIDATION_FAILED',
          message: err,
          path: 'root',
          severity: 'error' as const,
          category: 'schema' as const,
          suggestion: 'Check the configuration structure against the schema',
        }))
      );

      return this.buildValidationResult(startTime, errors, warnings, 0, 0, 0);
    }

    // Logic validation
    const logicErrors = await this.validateConfigurationLogic(validatedConfig);
    errors.push(...logicErrors);

    // Cross-reference validation
    const crossRefResult = await this.validateCrossReferences(validatedConfig);
    errors.push(...crossRefResult.errors);
    warnings.push(...crossRefResult.warnings);

    // Performance validation
    const perfResult = await this.validatePerformanceSettings(validatedConfig);
    warnings.push(...perfResult.warnings);

    // Security validation
    const securityResult = await this.validateSecuritySettings(validatedConfig);
    errors.push(...securityResult.errors);
    warnings.push(...securityResult.warnings);

    // Configuration quality checks
    const qualityWarnings = await this.validateConfigurationQuality(validatedConfig);
    warnings.push(...qualityWarnings);

    const performance = {
      validationTimeMs: Date.now() - startTime,
      rulesChecked: this.countRules(validatedConfig),
      attributesValidated: Object.keys(validatedConfig.processing_config.attributes.schema).length,
      crossReferencesChecked: crossRefResult.totalChecks,
    };

    return this.buildValidationResult(
      startTime,
      errors,
      warnings,
      performance.rulesChecked,
      performance.attributesValidated,
      performance.crossReferencesChecked
    );
  }

  /**
   * Validate processing configuration tuning parameters
   */
  async validateProcessingConfigurationTuning(
    config: ProcessingConfigTuning | unknown,
    options: ValidationOptions = {}
  ): Promise<ValidationResult> {
    const startTime = Date.now();
    const errors: ValidationError[] = [];
    const warnings: ValidationWarning[] = [];

    let validatedConfig: ProcessingConfigTuning;

    // Schema validation
    try {
      validatedConfig = validateProcessingConfigTuning(config);
    } catch (error) {
      const schemaErrors = getProcessingConfigErrors(config);
      errors.push(
        ...schemaErrors.map((err) => ({
          code: 'PROCESSING_SCHEMA_VALIDATION_FAILED',
          message: err,
          path: 'root',
          severity: 'error' as const,
          category: 'schema' as const,
          suggestion: 'Check the processing configuration structure against the schema',
        }))
      );

      return this.buildValidationResult(startTime, errors, warnings, 0, 0, 0);
    }

    // Tuning parameter validation
    const tuningErrors = await this.validateTuningParameters(validatedConfig);
    errors.push(...tuningErrors.errors);
    warnings.push(...tuningErrors.warnings);

    // Performance consistency validation
    const consistencyWarnings = await this.validatePerformanceConsistency(validatedConfig);
    warnings.push(...consistencyWarnings);

    const performance = {
      validationTimeMs: Date.now() - startTime,
      rulesChecked: 0,
      attributesValidated: 0,
      crossReferencesChecked: 0,
    };

    return this.buildValidationResult(
      startTime,
      errors,
      warnings,
      performance.rulesChecked,
      performance.attributesValidated,
      performance.crossReferencesChecked
    );
  }

  /**
   * Validate domain sources configuration
   */
  async validateDomainSources(
    config: Record<string, string[]> | unknown,
    options: ValidationOptions = {}
  ): Promise<ValidationResult> {
    const startTime = Date.now();
    const errors: ValidationError[] = [];
    const warnings: ValidationWarning[] = [];

    if (!config || typeof config !== 'object') {
      errors.push({
        code: 'INVALID_DOMAIN_SOURCES_TYPE',
        message: 'Domain sources must be an object',
        path: 'root',
        severity: 'error',
        category: 'schema',
      });
      return this.buildValidationResult(startTime, errors, warnings, 0, 0, 0);
    }

    const domainSources = config as Record<string, string[]>;

    // Validate domain groups
    for (const [groupName, domains] of Object.entries(domainSources)) {
      if (!Array.isArray(domains)) {
        errors.push({
          code: 'INVALID_DOMAIN_GROUP_TYPE',
          message: `Domain group "${groupName}" must be an array`,
          path: groupName,
          severity: 'error',
          category: 'schema',
        });
        continue;
      }

      // Validate individual domains
      for (let i = 0; i < domains.length; i++) {
        const domain = domains[i];
        if (typeof domain !== 'string') {
          errors.push({
            code: 'INVALID_DOMAIN_TYPE',
            message: `Domain at index ${i} in group "${groupName}" must be a string`,
            path: `${groupName}[${i}]`,
            severity: 'error',
            category: 'schema',
          });
          continue;
        }

        // Validate domain format
        if (!/^[a-zA-Z0-9.-]+\.[a-zA-Z]{2,}$/.test(domain)) {
          errors.push({
            code: 'INVALID_DOMAIN_FORMAT',
            message: `Invalid domain format: "${domain}" in group "${groupName}"`,
            path: `${groupName}[${i}]`,
            severity: 'error',
            category: 'logic',
            suggestion: 'Use valid domain format like "example.com"',
          });
        }
      }

      // Check for duplicate domains within group
      const uniqueDomains = new Set(domains);
      if (uniqueDomains.size !== domains.length) {
        warnings.push({
          code: 'DUPLICATE_DOMAINS_IN_GROUP',
          message: `Group "${groupName}" contains duplicate domains`,
          path: groupName,
          impact: 'low',
          recommendation: 'Remove duplicate domains to improve configuration clarity',
        });
      }
    }

    // Check for domains appearing in multiple groups
    const allDomains = new Map<string, string[]>();
    for (const [groupName, domains] of Object.entries(domainSources)) {
      for (const domain of domains) {
        if (!allDomains.has(domain)) {
          allDomains.set(domain, []);
        }
        allDomains.get(domain)!.push(groupName);
      }
    }

    for (const [domain, groups] of allDomains) {
      if (groups.length > 1) {
        warnings.push({
          code: 'DOMAIN_IN_MULTIPLE_GROUPS',
          message: `Domain "${domain}" appears in multiple groups: ${groups.join(', ')}`,
          path: 'cross-reference',
          impact: 'medium',
          recommendation: 'Consider if this domain should only be in one group for clarity',
        });
      }
    }

    return this.buildValidationResult(startTime, errors, warnings, 0, 0, allDomains.size);
  }

  /**
   * Validate complete configuration suite (category + processing + domains)
   */
  async validateCompleteConfiguration(
    categoryConfig: CategoryConfiguration,
    processingConfig: ProcessingConfigTuning,
    domainSources: Record<string, string[]>,
    options: ValidationOptions = {}
  ): Promise<ValidationResult> {
    const startTime = Date.now();
    const errors: ValidationError[] = [];
    const warnings: ValidationWarning[] = [];

    // Validate individual configurations
    const categoryResult = await this.validateCategoryConfiguration(categoryConfig, options);
    const processingResult = await this.validateProcessingConfigurationTuning(processingConfig, options);
    const domainResult = await this.validateDomainSources(domainSources, options);

    errors.push(...categoryResult.errors, ...processingResult.errors, ...domainResult.errors);
    warnings.push(...categoryResult.warnings, ...processingResult.warnings, ...domainResult.warnings);

    // Cross-configuration validation
    const crossConfigErrors = await this.validateCrossConfigurationReferences(
      categoryConfig,
      processingConfig,
      domainSources
    );
    errors.push(...crossConfigErrors);

    const totalChecks =
      categoryResult.performance.crossReferencesChecked +
      processingResult.performance.crossReferencesChecked +
      domainResult.performance.crossReferencesChecked;

    return this.buildValidationResult(
      startTime,
      errors,
      warnings,
      categoryResult.performance.rulesChecked,
      categoryResult.performance.attributesValidated,
      totalChecks
    );
  }

  // Private validation methods

  private async validateConfigurationLogic(config: CategoryConfiguration): Promise<ValidationError[]> {
    const errors: ValidationError[] = [];

    // Validate category consistency
    for (const [categoryName, category] of Object.entries(config.processing_config.top_level_categories)) {
      // Check if category has signals
      if (!config.processing_config.category_signals[categoryName]) {
        errors.push({
          code: 'MISSING_CATEGORY_SIGNALS',
          message: `Category "${categoryName}" has no signals defined`,
          path: `top_level_categories.${categoryName}`,
          severity: 'error',
          category: 'logic',
          suggestion: 'Add category signals or remove the category definition',
        });
      }

      // Validate subtypes
      for (const [subtypeName, subtype] of Object.entries(category.subtypes)) {
        if (subtype.derived && !subtype.derivation_logic) {
          errors.push({
            code: 'MISSING_DERIVATION_LOGIC',
            message: `Derived subtype "${categoryName}.${subtypeName}" has no derivation logic`,
            path: `top_level_categories.${categoryName}.subtypes.${subtypeName}`,
            severity: 'error',
            category: 'logic',
            suggestion: 'Add derivation_logic or set derived to false',
          });
        }
      }
    }

    return errors;
  }

  private async validateCrossReferences(config: CategoryConfiguration): Promise<{
    errors: ValidationError[];
    warnings: ValidationWarning[];
    totalChecks: number;
  }> {
    const errors: ValidationError[] = [];
    const warnings: ValidationWarning[] = [];
    let totalChecks = 0;

    // Get defined attributes
    const definedAttributes = new Set(Object.keys(config.processing_config.attributes.schema));

    // Check attribute references in relevance matrix
    for (const [categoryName, categoryConfig] of Object.entries(config.processing_config.attribute_relevance)) {
      if (categoryName === '_roles_legend') continue;

      totalChecks++;

      if (categoryConfig.category_roles) {
        for (const attributeName of Object.keys(categoryConfig.category_roles)) {
          totalChecks++;
          if (!definedAttributes.has(attributeName)) {
            errors.push({
              code: 'UNDEFINED_ATTRIBUTE_REFERENCE',
              message: `Category "${categoryName}" references undefined attribute: "${attributeName}"`,
              path: `attribute_relevance.${categoryName}.category_roles.${attributeName}`,
              severity: 'error',
              category: 'reference',
              suggestion: `Define attribute "${attributeName}" in attributes.schema or remove the reference`,
            });
          }
        }
      }
    }

    // Check for orphaned attributes (defined but not used)
    const usedAttributes = new Set<string>();
    for (const [categoryName, categoryConfig] of Object.entries(config.processing_config.attribute_relevance)) {
      if (categoryName === '_roles_legend') continue;
      // Type guard to ensure we have the correct structure
      if (typeof categoryConfig === 'object' && categoryConfig !== null && 'category_roles' in categoryConfig) {
        if (categoryConfig.category_roles) {
          Object.keys(categoryConfig.category_roles).forEach((attr) => usedAttributes.add(attr));
        }
      }
    }

    for (const attributeName of definedAttributes) {
      totalChecks++;
      if (!usedAttributes.has(attributeName)) {
        warnings.push({
          code: 'ORPHANED_ATTRIBUTE',
          message: `Attribute "${attributeName}" is defined but not used in any category`,
          path: `attributes.schema.${attributeName}`,
          impact: 'low',
          recommendation: 'Consider removing unused attributes or adding them to relevance matrix',
        });
      }
    }

    return { errors, warnings, totalChecks };
  }

  private async validatePerformanceSettings(config: CategoryConfiguration): Promise<{
    warnings: ValidationWarning[];
  }> {
    const warnings: ValidationWarning[] = [];

    // Check for performance optimization opportunities
    const totalRules = this.countRules(config);
    if (totalRules > 1000) {
      warnings.push({
        code: 'HIGH_RULE_COUNT',
        message: `Configuration has ${totalRules} rules, which may impact performance`,
        path: 'top_level_categories',
        impact: 'medium',
        recommendation: 'Consider optimizing rules or enabling rule compilation',
      });
    }

    const totalCategories = Object.keys(config.processing_config.top_level_categories).length;
    if (totalCategories > 20) {
      warnings.push({
        code: 'HIGH_CATEGORY_COUNT',
        message: `Configuration has ${totalCategories} categories, which may impact classification performance`,
        path: 'top_level_categories',
        impact: 'medium',
        recommendation: 'Consider consolidating related categories',
      });
    }

    return { warnings };
  }

  private async validateSecuritySettings(config: CategoryConfiguration): Promise<{
    errors: ValidationError[];
    warnings: ValidationWarning[];
  }> {
    const errors: ValidationError[] = [];
    const warnings: ValidationWarning[] = [];

    // Check for potentially dangerous regex patterns
    for (const [categoryName, category] of Object.entries(config.processing_config.top_level_categories)) {
      for (const [subtypeName, subtype] of Object.entries(category.subtypes)) {
        if (subtype.rule_based_classification) {
          for (const [tier, rules] of Object.entries(subtype.rule_based_classification)) {
            if (rules) {
              for (const rule of rules) {
                if (rule.operation === 'regex_any' && rule.values) {
                  for (const pattern of rule.values) {
                    if (this.isDangerousRegex(pattern)) {
                      warnings.push({
                        code: 'DANGEROUS_REGEX_PATTERN',
                        message: `Potentially dangerous regex pattern in ${categoryName}.${subtypeName}.${tier}: "${pattern}"`,
                        path: `top_level_categories.${categoryName}.subtypes.${subtypeName}.rule_based_classification.${tier}`,
                        impact: 'high',
                        recommendation: 'Review regex pattern for potential ReDoS vulnerability',
                      });
                    }
                  }
                }
              }
            }
          }
        }
      }
    }

    return { errors, warnings };
  }

  private async validateConfigurationQuality(config: CategoryConfiguration): Promise<ValidationWarning[]> {
    const warnings: ValidationWarning[] = [];

    // Check for empty categories
    for (const [categoryName, category] of Object.entries(config.processing_config.top_level_categories)) {
      if (Object.keys(category.subtypes).length === 0) {
        warnings.push({
          code: 'EMPTY_CATEGORY',
          message: `Category "${categoryName}" has no subtypes defined`,
          path: `top_level_categories.${categoryName}`,
          impact: 'medium',
          recommendation: 'Add subtypes or remove the empty category',
        });
      }
    }

    // Check for categories without AI classification
    for (const [categoryName, category] of Object.entries(config.processing_config.top_level_categories)) {
      if (!category.ai_final_classification.decision_criteria.length) {
        warnings.push({
          code: 'MISSING_AI_CRITERIA',
          message: `Category "${categoryName}" has no AI decision criteria`,
          path: `top_level_categories.${categoryName}.ai_final_classification`,
          impact: 'medium',
          recommendation: 'Add decision criteria for AI classification fallback',
        });
      }
    }

    return warnings;
  }

  private async validateTuningParameters(config: ProcessingConfigTuning): Promise<{
    errors: ValidationError[];
    warnings: ValidationWarning[];
  }> {
    const errors: ValidationError[] = [];
    const warnings: ValidationWarning[] = [];

    // Validate threshold relationships
    if (config.ai_routing_tuning) {
      const ai = config.ai_routing_tuning;
      if (ai.high_confidence_threshold <= ai.ai_required_threshold) {
        errors.push({
          code: 'INVALID_THRESHOLD_RELATIONSHIP',
          message: 'high_confidence_threshold must be greater than ai_required_threshold',
          path: 'ai_routing_tuning',
          severity: 'error',
          category: 'logic',
          suggestion: 'Adjust thresholds so high_confidence_threshold > ai_required_threshold',
        });
      }
    }

    // Validate performance settings
    if (config.performance_tuning) {
      const perf = config.performance_tuning;
      if (perf.max_parallel_emails && perf.email_batch_size) {
        if (perf.max_parallel_emails > perf.email_batch_size) {
          warnings.push({
            code: 'INEFFICIENT_PARALLEL_SETTINGS',
            message: 'max_parallel_emails exceeds email_batch_size',
            path: 'performance_tuning',
            impact: 'medium',
            recommendation: 'Set max_parallel_emails <= email_batch_size for optimal batching',
          });
        }
      }
    }

    return { errors, warnings };
  }

  private async validatePerformanceConsistency(config: ProcessingConfigTuning): Promise<ValidationWarning[]> {
    const warnings: ValidationWarning[] = [];

    // Check for conflicting performance settings
    if (config.performance_tuning?.parallel_processing_enabled === false) {
      if (config.attribute_detection_tuning?.parallel_detection_enabled === true) {
        warnings.push({
          code: 'CONFLICTING_PARALLEL_SETTINGS',
          message: 'Global parallel processing is disabled but attribute detection parallelism is enabled',
          path: 'performance_tuning.parallel_processing_enabled',
          impact: 'medium',
          recommendation: 'Align parallel processing settings for consistency',
        });
      }
    }

    return warnings;
  }

  private async validateCrossConfigurationReferences(
    categoryConfig: CategoryConfiguration,
    processingConfig: ProcessingConfigTuning,
    domainSources: Record<string, string[]>
  ): Promise<ValidationError[]> {
    const errors: ValidationError[] = [];

    // Validate domain references
    const availableDomainGroups = new Set(Object.keys(domainSources));

    for (const [categoryName, signals] of Object.entries(categoryConfig.processing_config.category_signals)) {
      if (signals.hard_assertions?.from_domains_ref) {
        const groupName = signals.hard_assertions.from_domains_ref.source_group;
        if (!availableDomainGroups.has(groupName)) {
          errors.push({
            code: 'INVALID_DOMAIN_GROUP_REFERENCE',
            message: `Category "${categoryName}" references undefined domain group: "${groupName}"`,
            path: `category_signals.${categoryName}.hard_assertions.from_domains_ref.source_group`,
            severity: 'error',
            category: 'reference',
            suggestion: `Define domain group "${groupName}" in domain sources or update the reference`,
          });
        }
      }
    }

    return errors;
  }

  private countRules(config: CategoryConfiguration): number {
    let count = 0;
    for (const category of Object.values(config.processing_config.top_level_categories)) {
      for (const subtype of Object.values(category.subtypes)) {
        if (subtype.rule_based_classification) {
          for (const rules of Object.values(subtype.rule_based_classification)) {
            if (rules) {
              count += rules.length;
            }
          }
        }
      }
    }
    return count;
  }

  private isDangerousRegex(pattern: string): boolean {
    // Basic check for potentially dangerous regex patterns
    const dangerousPatterns = [
      /\(.*\+.*\).*\+/, // Nested quantifiers
      /\(.*\*.*\).*\*/, // Nested quantifiers
      /\([^)]*\+[^)]*\)\+/, // Nested quantifiers
      /\([^)]*\*[^)]*\)\*/, // Nested quantifiers
    ];

    return dangerousPatterns.some((dangerous) => dangerous.test(pattern));
  }

  private buildValidationResult(
    startTime: number,
    errors: ValidationError[],
    warnings: ValidationWarning[],
    rulesChecked: number,
    attributesValidated: number,
    crossReferencesChecked: number
  ): ValidationResult {
    const criticalIssues = errors.filter((e) => e.severity === 'error').length;
    const totalErrors = errors.length;
    const totalWarnings = warnings.length;

    let configurationHealth: 'excellent' | 'good' | 'fair' | 'poor';
    if (criticalIssues === 0 && totalWarnings === 0) {
      configurationHealth = 'excellent';
    } else if (criticalIssues === 0 && totalWarnings <= 3) {
      configurationHealth = 'good';
    } else if (criticalIssues <= 2 && totalWarnings <= 10) {
      configurationHealth = 'fair';
    } else {
      configurationHealth = 'poor';
    }

    const recommendedActions: string[] = [];
    if (criticalIssues > 0) {
      recommendedActions.push(`Fix ${criticalIssues} critical error(s)`);
    }
    if (totalWarnings > 5) {
      recommendedActions.push('Review and address configuration warnings');
    }
    if (configurationHealth === 'poor') {
      recommendedActions.push('Consider restructuring configuration for better maintainability');
    }

    return {
      isValid: criticalIssues === 0,
      errors,
      warnings,
      performance: {
        validationTimeMs: Date.now() - startTime,
        rulesChecked,
        attributesValidated,
        crossReferencesChecked,
      },
      summary: {
        totalErrors,
        totalWarnings,
        criticalIssues,
        configurationHealth,
        recommendedActions,
      },
    };
  }
}

// Default validator instance
export const configValidator = new ConfigurationValidator();

import { z } from 'zod';

/**
 * Zod schema for ProcessingConfig validation
 * Includes all tuning parameters per ${repoRoot}/docs/SCORING_LOGIC.md throughout
 */

// Base validation schemas
const PositiveNumberSchema = z.number().min(0);
const ProbabilitySchema = z.number().min(0).max(1);
const WeightSchema = z.number().min(0).max(2);
const IntegerSchema = z.number().int();
const PositiveIntegerSchema = z.number().int().min(1);

// Tuning parameter schemas for individual stages
const HardAssertionTuningSchema = z.object({
  high_confidence_floor: ProbabilitySchema.default(0.9),
  domain_confidence_boost: z.number().min(0).max(0.2).default(0.1),
  subject_prefix_boost: z.number().min(0).max(0.15).default(0.1),
  from_address_boost: z.number().min(0).max(0.1).default(0.05),
  parallel_processing_enabled: z.boolean().default(true),
});

const StrongIndicatorTuningSchema = z.object({
  base_seed_value: ProbabilitySchema.default(0.6),
  diminishing_returns: z.object({
    enabled: z.boolean().default(true),
    decay_factor: z.number().min(0.1).max(0.9).default(0.8),
    max_indicators: PositiveIntegerSchema.default(5),
    minimum_value_threshold: z.number().min(0).max(0.1).default(0.05),
  }),
  domain_weight_multiplier: WeightSchema.default(1.2),
  content_weight_multiplier: WeightSchema.default(1.0),
  parallel_seeding_enabled: z.boolean().default(true),
});

const RuleScoringTuningSchema = z.object({
  // Subtype scoring formula parameters (K_high, K_medium, K_low)
  K_high: PositiveNumberSchema.default(1.0),
  K_medium: PositiveNumberSchema.default(0.7),
  K_low: PositiveNumberSchema.default(0.3),

  // Bounded aggregation parameters
  aggregation_cap: ProbabilitySchema.default(1.0),
  saturation_threshold: ProbabilitySchema.default(0.95),
  diminishing_factor: z.number().min(0.5).max(1.0).default(0.9),

  // Rule evaluation settings
  lexical_pattern_weight: WeightSchema.default(1.0),
  subtype_rule_weight: WeightSchema.default(1.0),
  case_sensitivity: z.boolean().default(false),
  word_boundary_matching: z.boolean().default(true),

  // Performance optimization
  parallel_rule_evaluation: z.boolean().default(true),
  max_parallel_rules: PositiveIntegerSchema.default(10),
  rule_cache_enabled: z.boolean().default(true),
  cache_size_limit: PositiveIntegerSchema.default(1000),
});

const AttributeDetectionTuningSchema = z.object({
  // Detection confidence thresholds
  minimum_detection_confidence: ProbabilitySchema.default(0.7),
  high_confidence_threshold: ProbabilitySchema.default(0.9),

  // Attribute-specific settings
  self_sent_detection: z.object({
    enabled: z.boolean().default(true),
    confidence_boost: z.number().min(0).max(0.2).default(0.1),
    domain_whitelist: z.array(z.string()).default([]),
  }),

  domain_resolution: z.object({
    enabled: z.boolean().default(true),
    cache_enabled: z.boolean().default(true),
    cache_ttl_seconds: PositiveIntegerSchema.default(3600),
    timeout_ms: PositiveIntegerSchema.default(5000),
  }),

  context_flags: z.object({
    urgency_detection_enabled: z.boolean().default(true),
    structural_pattern_detection: z.boolean().default(true),
    temporal_signal_detection: z.boolean().default(true),
  }),

  // Parallel processing
  parallel_detection_enabled: z.boolean().default(true),
  max_parallel_detectors: PositiveIntegerSchema.default(5),
  detector_timeout_ms: PositiveIntegerSchema.default(10000),
});

const AttributeInfluenceTuningSchema = z.object({
  // Bonus and penalty application
  bonus_multiplier: WeightSchema.default(1.0),
  penalty_multiplier: WeightSchema.default(1.0),

  // Influence caps per role type
  core_attribute_max_influence: ProbabilitySchema.default(0.4),
  primary_boost_max_influence: ProbabilitySchema.default(0.3),
  secondary_boost_max_influence: ProbabilitySchema.default(0.2),
  disambiguator_max_influence: ProbabilitySchema.default(0.15),
  filter_max_influence: ProbabilitySchema.default(0.1),

  // Total influence limits
  max_total_bonus: ProbabilitySchema.default(0.5),
  max_total_penalty: ProbabilitySchema.default(0.3),

  // Role enforcement
  strict_role_enforcement: z.boolean().default(true),
  fallback_to_neutral_on_conflict: z.boolean().default(true),

  // Parallel processing
  parallel_influence_calculation: z.boolean().default(true),
  influence_cache_enabled: z.boolean().default(true),
});

const DisambiguationTuningSchema = z.object({
  // Pairwise adjustment thresholds
  confidence_gap_threshold: ProbabilitySchema.default(0.1),
  minimum_adjustment_threshold: z.number().min(0).max(0.1).default(0.02),
  maximum_adjustment_per_pair: ProbabilitySchema.default(0.2),

  // Adjustment limits
  max_adjustments_per_category: PositiveIntegerSchema.default(3),
  total_adjustment_cap: ProbabilitySchema.default(0.3),

  // Disambiguation strategies
  pairwise_adjustments_enabled: z.boolean().default(true),
  context_aware_disambiguation: z.boolean().default(true),
  temporal_disambiguation: z.boolean().default(false),

  // Performance settings
  max_disambiguation_iterations: PositiveIntegerSchema.default(5),
  convergence_threshold: z.number().min(0).max(0.01).default(0.001),
});

const MultiLabelTuningSchema = z.object({
  // Selection thresholds
  min_secondary_confidence: ProbabilitySchema.default(0.6),
  confidence_gap_minimum: ProbabilitySchema.default(0.15),
  max_confidence_sum: PositiveNumberSchema.default(2.0),

  // Label limits
  max_labels: PositiveIntegerSchema.default(3),
  max_top_level_labels: PositiveIntegerSchema.default(2),

  // Co-presence rules
  financial_actionable_copresence_allowed: z.boolean().default(false),
  category_combination_penalties: z.record(z.string(), z.number().min(0).max(0.5)).default({}),

  // Quality controls
  minimum_primary_lead: ProbabilitySchema.default(0.1),
  secondary_confidence_decay: z.number().min(0.5).max(1.0).default(0.9),
  label_coherence_check: z.boolean().default(true),
});

const AIRoutingTuningSchema = z.object({
  // Routing thresholds
  high_confidence_threshold: ProbabilitySchema.default(0.8),
  ai_required_threshold: ProbabilitySchema.default(0.4),
  manual_review_threshold: ProbabilitySchema.default(0.2),

  // AI service configuration
  model_settings: z.object({
    primary_model: z.string().default('gpt-4'),
    fallback_model: z.string().default('gpt-3.5-turbo'),
    temperature: z.number().min(0).max(2).default(0.1),
    max_tokens: PositiveIntegerSchema.default(500),
    timeout_ms: PositiveIntegerSchema.default(30000),
  }),

  // Batch processing
  batch_size: PositiveIntegerSchema.default(10),
  batch_timeout_ms: PositiveIntegerSchema.default(60000),
  parallel_ai_requests: z.boolean().default(true),
  max_parallel_requests: PositiveIntegerSchema.default(5),

  // Skip conditions
  skip_ai_conditions: z
    .array(
      z.enum([
        'high_confidence_achieved',
        'single_strong_category',
        'hard_assertion_match',
        'manual_review_flagged',
        'processing_time_exceeded',
      ])
    )
    .default([]),

  // Quality controls
  ai_confidence_threshold: ProbabilitySchema.default(0.7),
  consistency_check_enabled: z.boolean().default(true),
  fallback_to_rule_based: z.boolean().default(true),
});

const AuditTrailTuningSchema = z.object({
  // Explainability trace configuration
  generate_full_trace: z.boolean().default(true),
  include_stage_timings: z.boolean().default(true),
  include_parallel_execution_map: z.boolean().default(true),
  include_configuration_refs: z.boolean().default(true),

  // Trace detail levels
  rule_evaluation_details: z.enum(['minimal', 'standard', 'verbose']).default('standard'),
  attribute_detection_details: z.enum(['minimal', 'standard', 'verbose']).default('standard'),
  score_breakdown_precision: PositiveIntegerSchema.default(4),

  // Performance optimization
  trace_compression_enabled: z.boolean().default(false),
  async_trace_writing: z.boolean().default(true),
  trace_batching_enabled: z.boolean().default(true),
  batch_size: PositiveIntegerSchema.default(50),

  // Retention settings
  trace_retention_days: PositiveIntegerSchema.default(90),
  archive_old_traces: z.boolean().default(true),
  compression_after_days: PositiveIntegerSchema.default(30),
});

// Performance and parallelism settings
const PerformanceTuningSchema = z.object({
  // Global parallel processing
  parallel_processing_enabled: z.boolean().default(true),
  max_parallel_emails: PositiveIntegerSchema.default(10),
  email_batch_size: PositiveIntegerSchema.default(50),

  // Stage-specific parallelism
  parallel_stages: z
    .array(
      z.enum([
        'attribute_detection',
        'rule_evaluation',
        'influence_calculation',
        'ai_routing',
        'audit_trail_generation',
      ])
    )
    .default(['attribute_detection', 'rule_evaluation']),

  // Memory management
  memory_limit_mb: PositiveIntegerSchema.default(512),
  gc_threshold_mb: PositiveIntegerSchema.default(256),
  cache_size_limits: z.object({
    rule_cache_mb: PositiveIntegerSchema.default(64),
    attribute_cache_mb: PositiveIntegerSchema.default(32),
    config_cache_mb: PositiveIntegerSchema.default(16),
  }),

  // Timeout settings
  total_processing_timeout_ms: PositiveIntegerSchema.default(60000),
  stage_timeout_ms: PositiveIntegerSchema.default(10000),
  database_timeout_ms: PositiveIntegerSchema.default(5000),

  // Optimization flags
  enable_caching: z.boolean().default(true),
  enable_memoization: z.boolean().default(true),
  enable_lazy_loading: z.boolean().default(true),
  precompile_rules: z.boolean().default(true),
});

// Main processing configuration schema with all tuning parameters
export const ProcessingConfigTuningSchema = z.object({
  // Global settings
  version: PositiveIntegerSchema,
  schema_version: z.string().default('1.0.0'),
  taxonomy_notes: z.string(),

  // Stage-specific tuning parameters
  hard_assertion_tuning: HardAssertionTuningSchema.optional().default({}),
  strong_indicator_tuning: StrongIndicatorTuningSchema.optional().default({}),
  rule_scoring_tuning: RuleScoringTuningSchema.optional().default({}),
  attribute_detection_tuning: AttributeDetectionTuningSchema.optional().default({}),
  attribute_influence_tuning: AttributeInfluenceTuningSchema.optional().default({}),
  disambiguation_tuning: DisambiguationTuningSchema.optional().default({}),
  multi_label_tuning: MultiLabelTuningSchema.optional().default({}),
  ai_routing_tuning: AIRoutingTuningSchema.optional().default({}),
  audit_trail_tuning: AuditTrailTuningSchema.optional().default({}),

  // Performance and system tuning
  performance_tuning: PerformanceTuningSchema.optional().default({}),

  // Validation settings
  strict_validation: z.boolean().default(true),
  allow_experimental_features: z.boolean().default(false),
  compatibility_mode: z.enum(['strict', 'permissive', 'legacy']).default('strict'),

  // Monitoring and debugging
  monitoring: z
    .object({
      enable_metrics_collection: z.boolean().default(true),
      detailed_timing: z.boolean().default(false),
      memory_tracking: z.boolean().default(false),
      error_tracking: z.boolean().default(true),
      performance_alerts: z
        .object({
          slow_processing_threshold_ms: PositiveIntegerSchema.default(30000),
          high_memory_threshold_mb: PositiveIntegerSchema.default(256),
          error_rate_threshold: ProbabilitySchema.default(0.05),
        })
        .default({}),
    })
    .default({}),
});

// Simplified schema for basic processing config (backward compatibility)
export const BasicProcessingConfigSchema = z.object({
  version: PositiveIntegerSchema,
  taxonomy_notes: z.string(),

  // Essential settings only
  settings: z.object({
    initialization: z.object({
      apply_hard_assertions: z.boolean().default(true),
      seed_category_scores: z.boolean().default(true),
    }),
    rule_scoring: z.object({
      use_lexical_patterns: z.boolean().default(true),
      apply_subtype_rules: z.boolean().default(true),
      bounded_aggregation: z.boolean().default(true),
    }),
    attribute_processing: z.object({
      detect_self_sent: z.boolean().default(true),
      resolve_domains: z.boolean().default(true),
      derive_context_flags: z.boolean().default(true),
    }),
    disambiguation: z.object({
      pairwise_adjustments: z.boolean().default(true),
      confidence_gap_threshold: ProbabilitySchema.default(0.1),
    }),
    multi_label_selection: z.object({
      max_labels: PositiveIntegerSchema.default(3),
      min_secondary_confidence: ProbabilitySchema.default(0.6),
    }),
    ai_routing: z.object({
      high_confidence_threshold: ProbabilitySchema.default(0.8),
      ai_required_threshold: ProbabilitySchema.default(0.4),
    }),
  }),

  // Basic performance settings
  performance: z
    .object({
      parallel_processing: z.boolean().default(true),
      batch_size: PositiveIntegerSchema.default(50),
      timeout_ms: PositiveIntegerSchema.default(60000),
    })
    .default({}),
});

// Type inference
export type ProcessingConfigTuning = z.infer<typeof ProcessingConfigTuningSchema>;
export type BasicProcessingConfig = z.infer<typeof BasicProcessingConfigSchema>;
export type HardAssertionTuning = z.infer<typeof HardAssertionTuningSchema>;
export type StrongIndicatorTuning = z.infer<typeof StrongIndicatorTuningSchema>;
export type RuleScoringTuning = z.infer<typeof RuleScoringTuningSchema>;
export type AttributeDetectionTuning = z.infer<typeof AttributeDetectionTuningSchema>;
export type AttributeInfluenceTuning = z.infer<typeof AttributeInfluenceTuningSchema>;
export type DisambiguationTuning = z.infer<typeof DisambiguationTuningSchema>;
export type MultiLabelTuning = z.infer<typeof MultiLabelTuningSchema>;
export type AIRoutingTuning = z.infer<typeof AIRoutingTuningSchema>;
export type AuditTrailTuning = z.infer<typeof AuditTrailTuningSchema>;
export type PerformanceTuning = z.infer<typeof PerformanceTuningSchema>;

// Validation helper functions
export const validateProcessingConfigTuning = (config: unknown): ProcessingConfigTuning => {
  return ProcessingConfigTuningSchema.parse(config);
};

export const validateBasicProcessingConfig = (config: unknown): BasicProcessingConfig => {
  return BasicProcessingConfigSchema.parse(config);
};

// Tuning parameter validation helpers
export const validateHardAssertionTuning = (tuning: unknown): HardAssertionTuning => {
  return HardAssertionTuningSchema.parse(tuning);
};

export const validateRuleScoringTuning = (tuning: unknown): RuleScoringTuning => {
  return RuleScoringTuningSchema.parse(tuning);
};

export const validateAttributeInfluenceTuning = (tuning: unknown): AttributeInfluenceTuning => {
  return AttributeInfluenceTuningSchema.parse(tuning);
};

export const validatePerformanceTuning = (tuning: unknown): PerformanceTuning => {
  return PerformanceTuningSchema.parse(tuning);
};

// Configuration validation utilities
export const isValidProcessingConfig = (config: unknown): boolean => {
  try {
    ProcessingConfigTuningSchema.parse(config);
    return true;
  } catch {
    return false;
  }
};

export const getProcessingConfigErrors = (config: unknown): string[] => {
  try {
    ProcessingConfigTuningSchema.parse(config);
    return [];
  } catch (error) {
    if (error instanceof z.ZodError) {
      return error.errors.map((err) => `${err.path.join('.')}: ${err.message}`);
    }
    return ['Unknown validation error'];
  }
};

